class Solution:
    def moveZeroes(self, nums):
        # Independent: build the compacted list, then copy back in place.
        nonzero = [x for x in nums if x != 0]
        zeros = len(nums) - len(nonzero)
        result = nonzero + [0] * zeros
        for i in range(len(nums)):
            nums[i] = result[i]

