var moveZeroes = function(nums) {
    let slot = 0;
    for (let i = 0; i < nums.length; i++) {
        if (nums[i] !== 0) {
            [nums[slot], nums[i]] = [nums[i], nums[slot]];
            slot++;
        }
    }
